import{_ as a,o as n,c as l,ak as o}from"./chunks/framework.DLt_otXO.js";const i=JSON.parse('{"title":"SQL 语言","description":"","frontmatter":{},"headers":[],"relativePath":"java/mysql/SQL语言.md","filePath":"java/mysql/SQL语言.md","lastUpdated":1777258973000}'),e={name:"java/mysql/SQL语言.md"};function p(t,s,c,r,E,y){return n(),l("div",null,[...s[0]||(s[0]=[o(`<h1 id="sql-语言" tabindex="-1">SQL 语言 <a class="header-anchor" href="#sql-语言" aria-label="Permalink to “SQL 语言”">​</a></h1><h2 id="_1-前言" tabindex="-1">1. 前言 <a class="header-anchor" href="#_1-前言" aria-label="Permalink to “1. 前言”">​</a></h2><p><code>SQL</code>程序语言有<strong>四种</strong>类型，对数据库的操作都属于这<strong>四类</strong>，它们分别是：数据定义语言(<code>DDL</code>)，数据查询语言(<code>DQL</code>)，数据操纵语言(<code>DML</code>)，数据控制语言(<code>DCL</code>)。</p><h2 id="_2-数据定义语言-ddl" tabindex="-1">2. 数据定义语言（DDL） <a class="header-anchor" href="#_2-数据定义语言-ddl" aria-label="Permalink to “2. 数据定义语言（DDL）”">​</a></h2><p><code>DDL</code>全称是<code>Data Definition Language</code>，即数据定义语言，定义语言就是定义关系模式、删除关系、修改关系模式以及创建数据库中的各种对象，比如表、聚簇、索引、视图、函数、存储过程和触发器等等。</p><p>数据定义语言是由<code>SQL</code>语言集中负责数据结构定义与数据库对象定义的语言，并且由<code>CREATE</code>、<code>ALTER</code>、<code>DROP</code>和<code>TRUNCATE</code>四个语法组成。比如：</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#6A737D;">-- 创建学生表</span></span>
<span class="line"><span style="color:#F97583;">create</span><span style="color:#F97583;"> table</span><span style="color:#B392F0;"> student</span><span style="color:#E1E4E8;">(</span></span>
<span class="line"><span style="color:#E1E4E8;">    id </span><span style="color:#F97583;">int</span><span style="color:#79B8FF;"> identity</span><span style="color:#E1E4E8;">(</span><span style="color:#79B8FF;">1</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">1</span><span style="color:#E1E4E8;">) </span><span style="color:#F97583;">not null</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#F97583;">    name</span><span style="color:#F97583;"> varchar</span><span style="color:#E1E4E8;">(</span><span style="color:#79B8FF;">20</span><span style="color:#E1E4E8;">) </span><span style="color:#F97583;">null</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">    course </span><span style="color:#F97583;">varchar</span><span style="color:#E1E4E8;">(</span><span style="color:#79B8FF;">20</span><span style="color:#E1E4E8;">) </span><span style="color:#F97583;">null</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">    grade </span><span style="color:#F97583;">numeric</span><span style="color:#F97583;"> null</span></span>
<span class="line"><span style="color:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">--student表增加一个年龄字段</span></span>
<span class="line"><span style="color:#F97583;">alter</span><span style="color:#F97583;"> table</span><span style="color:#E1E4E8;"> student </span><span style="color:#F97583;">add</span><span style="color:#E1E4E8;"> age </span><span style="color:#F97583;">int</span><span style="color:#F97583;"> NULL</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">--student表删除年龄字段，删除的字段前面需要加column</span></span>
<span class="line"><span style="color:#F97583;">alter</span><span style="color:#F97583;"> table</span><span style="color:#E1E4E8;"> student </span><span style="color:#F97583;">drop</span><span style="color:#E1E4E8;"> Column age</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">--删除表</span></span>
<span class="line"><span style="color:#F97583;">drop</span><span style="color:#F97583;"> table</span><span style="color:#E1E4E8;"> student </span><span style="color:#6A737D;">--删除表的数据和表的结构</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">--清空表的数据，，但并不删除表的结构，student表还在只是数据为空</span></span>
<span class="line"><span style="color:#F97583;">truncate</span><span style="color:#F97583;"> table</span><span style="color:#E1E4E8;"> student</span></span></code></pre></div><h2 id="_2-数据操纵语言-dml" tabindex="-1">2. 数据操纵语言(DML) <a class="header-anchor" href="#_2-数据操纵语言-dml" aria-label="Permalink to “2. 数据操纵语言(DML)”">​</a></h2><p>数据操纵语言全称是<code>Data Manipulation Language</code>，主要是进行插入元组、删除元组、修改元组的操作。主要有<code>insert</code>、<code>update</code>、<code>delete</code>语法组成。</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#6A737D;">--向student表中插入数据</span></span>
<span class="line"><span style="color:#F97583;">INSERT INTO</span><span style="color:#E1E4E8;"> student (</span><span style="color:#F97583;">name</span><span style="color:#E1E4E8;">, course,grade) </span><span style="color:#F97583;">VALUES</span><span style="color:#E1E4E8;"> </span></span>
<span class="line"><span style="color:#E1E4E8;">    (</span><span style="color:#9ECBFF;">&#39;张飞&#39;</span><span style="color:#E1E4E8;">,</span><span style="color:#9ECBFF;">&#39;语文&#39;</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">90</span><span style="color:#E1E4E8;">),(</span><span style="color:#9ECBFF;">&#39;刘备&#39;</span><span style="color:#E1E4E8;">,</span><span style="color:#9ECBFF;">&#39;数学&#39;</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">70</span><span style="color:#E1E4E8;">),(</span><span style="color:#9ECBFF;">&#39;关羽&#39;</span><span style="color:#E1E4E8;">,</span><span style="color:#9ECBFF;">&#39;历史&#39;</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">25</span><span style="color:#E1E4E8;">),(</span><span style="color:#9ECBFF;">&#39;张云&#39;</span><span style="color:#E1E4E8;">,</span><span style="color:#9ECBFF;">&#39;英语&#39;</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">13</span><span style="color:#E1E4E8;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">--更新student表数据</span></span>
<span class="line"><span style="color:#F97583;">update</span><span style="color:#E1E4E8;"> student </span><span style="color:#F97583;">set</span><span style="color:#E1E4E8;"> grade</span><span style="color:#F97583;">=</span><span style="color:#9ECBFF;">&#39;18&#39;</span><span style="color:#F97583;"> where</span><span style="color:#F97583;"> name=</span><span style="color:#9ECBFF;">&#39;关羽&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">-- 删除表数据</span></span>
<span class="line"><span style="color:#F97583;">delete</span><span style="color:#F97583;"> from</span><span style="color:#E1E4E8;"> student </span><span style="color:#F97583;">where</span><span style="color:#F97583;"> name=</span><span style="color:#9ECBFF;">&#39;关羽&#39;</span></span></code></pre></div><h2 id="_3-数据查询语言-dql" tabindex="-1">3. 数据查询语言(DQL) <a class="header-anchor" href="#_3-数据查询语言-dql" aria-label="Permalink to “3. 数据查询语言(DQL)”">​</a></h2><p>数据查询语言全称是<code>Data Query Language</code>，所以是用来进行数据库中数据的查询的，即最常用的<code>select</code>语句</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#6A737D;">--从student表中查询所有的数据</span></span>
<span class="line"><span style="color:#F97583;">select</span><span style="color:#F97583;"> *</span><span style="color:#F97583;"> from</span><span style="color:#E1E4E8;"> student</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">--从student表中查询姓名为张飞的学生</span></span>
<span class="line"><span style="color:#F97583;">select</span><span style="color:#F97583;"> *</span><span style="color:#F97583;"> from</span><span style="color:#E1E4E8;"> student </span><span style="color:#F97583;">where</span><span style="color:#F97583;"> name=</span><span style="color:#9ECBFF;">&#39;张飞&#39;</span></span></code></pre></div><h2 id="_4-数据控制语言-dcl" tabindex="-1">4.数据控制语言(DCL) <a class="header-anchor" href="#_4-数据控制语言-dcl" aria-label="Permalink to “4.数据控制语言(DCL)”">​</a></h2><p>数据控制语言：<code>Data Control Language</code>。用来授权或回收访问数据库的某种特权，并控制数据库操纵事务发生的时间及效果，能够对数据库进行监视。由 <code>GRANT</code> 和 <code>REVOKE</code> 两个指令组成</p><p>比如常见的授权、取消授权、回滚、提交等等操作。</p><h3 id="_1-给用户授权" tabindex="-1">1. 给用户授权 <a class="header-anchor" href="#_1-给用户授权" aria-label="Permalink to “1. 给用户授权”">​</a></h3><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">GRANT</span><span style="color:#E1E4E8;"> 权限1, … , 权限n </span><span style="color:#F97583;">ON</span><span style="color:#79B8FF;"> 数据库</span><span style="color:#E1E4E8;">.</span><span style="color:#79B8FF;">对象</span><span style="color:#F97583;">  TO</span><span style="color:#E1E4E8;"> 用户名;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">--将test数据库中所有对象(表、视图、存储过程，触发器等。*表示所有对象)的</span></span>
<span class="line"><span style="color:#6A737D;">-- create,alter,drop,insert,update,delete,select赋给testuser用户</span></span>
<span class="line"><span style="color:#F97583;">grant</span><span style="color:#F97583;"> create</span><span style="color:#E1E4E8;">,</span><span style="color:#F97583;">alter</span><span style="color:#E1E4E8;">,</span><span style="color:#F97583;">drop</span><span style="color:#E1E4E8;">,</span><span style="color:#F97583;">insert</span><span style="color:#E1E4E8;">,</span><span style="color:#F97583;">update</span><span style="color:#E1E4E8;">,</span><span style="color:#F97583;">delete</span><span style="color:#E1E4E8;">,</span><span style="color:#F97583;">select</span><span style="color:#F97583;"> on</span><span style="color:#E1E4E8;"> test.</span><span style="color:#F97583;">*</span><span style="color:#E1E4E8;"> </span></span>
<span class="line"><span style="color:#F97583;">    to</span><span style="color:#E1E4E8;"> testuser@localhost;</span></span></code></pre></div><h3 id="_2-撤销授权" tabindex="-1">2. 撤销授权 <a class="header-anchor" href="#_2-撤销授权" aria-label="Permalink to “2. 撤销授权”">​</a></h3><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#E1E4E8;">REVOKE权限1, … , 权限n </span><span style="color:#F97583;">ON</span><span style="color:#79B8FF;"> 数据库</span><span style="color:#E1E4E8;">.</span><span style="color:#79B8FF;">对象</span><span style="color:#E1E4E8;"> FORM 用户名;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">--收回用户对某个数据库的某个表的插入、更新、删除的权限</span></span>
<span class="line"><span style="color:#F97583;">REVOKE</span><span style="color:#F97583;"> INSERT</span><span style="color:#E1E4E8;">, </span><span style="color:#F97583;">UPDATE</span><span style="color:#E1E4E8;">, </span><span style="color:#F97583;">DELETE</span><span style="color:#F97583;"> ON</span><span style="color:#79B8FF;"> database_name</span><span style="color:#E1E4E8;">.</span><span style="color:#79B8FF;">table_name</span><span style="color:#E1E4E8;"> </span></span>
<span class="line"><span style="color:#F97583;">    FROM</span><span style="color:#9ECBFF;"> &#39;user_name&#39;</span><span style="color:#E1E4E8;">@</span><span style="color:#9ECBFF;">&#39;host&#39;</span><span style="color:#E1E4E8;">;</span></span></code></pre></div>`,20)])])}const F=a(e,[["render",p]]);export{i as __pageData,F as default};
